		-- {[1] = 10, __size = 1}
		unlockDesc = '特殊活动投放',
		unlockDesc_tw = '特殊活動投放',
		unlockDesc_vn = 'Put in for Special Event',
		unlockDesc_en = 'Put in for Special Event',
		unlockDesc_kr = '특수 이벤트 지급',
		unlockDesc_pt = 'Coloque em evento especial',
		unlockDesc_th = 'ใส่สำหรับกิจกรรมพิเศษ',
		activeCost = {[2273] = 1, __size = 1},
		attrType1 = 1,
		attrValue1 = '10%',
